  • 中国房产是政策驱动 > 市场驱动 —— 读政策、留余量、不赌政策: 中国房产市场是政策驱动多于市场驱动的市场 —— 限购/限贷/限售/认房认贷/LPR/参考价/房产税/保交楼都是可随时启用或急转的政策工具,「读政策原文」是核心能力;但读政策是为了「判方向、留余量」,不

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**签合同 + 网签备案**:签订买卖合同,办理网上签约备案(网签)—— 网签后房源被锁定,这是交易合法性的前置环节。签合同 ≠ 房子是你的,过户登记完成才是。inputs: 买卖合同;outputs: 网签备案号。"
  "**首付进资金监管账户**:首付款打入第三方资金监管账户(不是直接打给卖方),房款被监管,过户完成等条件满足才放款给卖方 —— 绝不走私下交易、无监管转账。inputs: 首付款;outputs: 资金进监管。"
  "**办贷款审批**:向银行提交贷款申请,银行审批(评估、征信、流水核查)—— 用真实材料,首付贷/假流水/经营贷置换是红线。inputs: 贷款材料;outputs: 贷款批复。"
  "**缴税过户**:在不动产登记中心办理过户登记,同步缴纳契税(买方)、增值税/个税(卖方税,常被转嫁给买方,合同里要写清谁承担)、中介费 —— 拿到新的不动产权证。inputs: 完税凭证;outputs: 不动产权属证书。"
  "**放款 + 监管解冻**:过户完成、抵押登记办妥后,银行放贷款尾款给卖方,资金监管账户按约定解冻 —— 交易完成。inputs: 过户证明;outputs: 交易闭环。"
)
declare -a FAILURE_MODES=(
  "**为省中介费走私下交易、不用资金监管**:触发原因 = 觉得「认识的人不会骗」;怎么避免 = 任何交易都走资金监管账户,房款进监管、过户完成才放款。Don't: 为省几千元监管/中介费私下转账给卖方,卖方拿钱后房子因抵押/查封过不了户,钱房两空。"
  "**税费谁承担只口头约定**:触发原因 = 嫌合同写太细;怎么避免 = 全部税费、承担方、上限、时间写进合同条款。"
  "**碰中介推销的「避税/融资技巧」**:触发原因 = 被「能省一大笔」吸引;怎么避免 = 阴阳合同/经营贷置换/首付贷一律识别为红线、拒绝。"
  "**没预审贷款资格就签约**:触发原因 = 默认「能贷下来」;怎么避免 = 出手前确认认房认贷口径和自己的贷款资格。"
  "**Decay risk**: medium —— 网签/资金监管/过户的核心流程稳定(low),但带押过户覆盖范围、LPR/首付/利率政策是高频变动项,整体 medium。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-4-walkthrough"
fi
